void qsort(int a[],int l,int r)
{
	if(l>=r)return;
	int i=l-1,j=r+1,x=a[(l+r)>>1];
	while(i<j)
	{
		do i++;while(x>a[i]);
		do j--;while(x<a[j]);
		if(i<j)swap(a[i],a[j]);
	}
	//cout<<i<<" "<<j<<endl;
	qsort(a,l,j);//不能写i 
	qsort(a,j+1,r);
}
void qsort2(int a[],int l,int r)
{
	if(l>=r)return;
	int i=l,j=r,x=a[(l+r)>>1];
	while(1)
	{
		while(x>a[i]) i++;
		while(x<a[j]) j--;
		if(i<j)
		{
			swap(a[i],a[j]);
			i++;j--;
		}
		else
		{
			break;
		}
	}
	//cout<<i<<" "<<j<<endl;
	qsort(a,l,j);//不能写i 
	qsort(a,j+1,r);
}
