### 786.第k个数

类似题：

#### [215. 数组中的第K个最大元素](https://leetcode.cn/problems/kth-largest-element-in-an-array/)

#### [剑指 Offer II 076. 数组中的第 k 大的数字](https://leetcode.cn/problems/xx4gT2/)

```c++
#include<iostream>
#include<cstdlib>
#include<cstdio>
#include<string>
#include<algorithm>
#include<cmath>
#include<vector>
#define debug(a) cout<<#a<<"="<<a<<endl
using namespace std;
const int N=100010;
int ncnt,n,k;
int a[N],flag=0;
int part(int a[],int low,int high)
{
	int randin=low+rand()%(high-low+1);
	swap(a[randin],a[low]);
	int pivot=a[low];
	int l=low,r=high;
	while(l<r)
	{
		while(l<r&&a[r]>pivot)r--;
		if(l<r)
		{
			a[l]=a[r];
			l++;
		}
		while(l<r&&a[l]<pivot)l++;
		if(l<r)
		{
			a[r]=a[l];
			r--;
		} 
	}
	a[l]=pivot;
//	for(int i=0;i<n;i++)
//		{
//			cout<<" "<<a[i]<<endl;
//		}
//	debug(l);
	return l;
}
int main()
{
	cin>>n>>k;
	for(int i=0;i<n;i++)
	{
		cin>>a[i];
	}
	int low=0,high=n-1;
	k--;
	while(low<high)
	{
		int pivot=part(a,low,high);
//		debug(pivot);
		if(pivot==k)
		{
			cout<<a[pivot]<<endl;
			flag=1;
			break;
		}
		else if(pivot<k)
		{
			low=pivot+1;
		}
		else
		{
			high=pivot-1;
		}
//		debug(high);
//		for(int i=0;i<n;i++)
//		{
//			cout<<" "<<a[i]<<endl;
//		}

	}
	if(!flag)cout<<a[low]<<endl;
	return 0;
}
