using namespace std;
const int N=100010;
int ncnt,n,k;
int a[N],flag=0;
int getk(int a[])
{
	priority_queue<int>q;
	for(int i=0;i<k;i++)
	{
		q.push(a[i]);
	}
	for(int i=k;i<n;i++)
	{
		int t=q.top();
		if(a[i]<q.top())
		{
			q.pop();
			q.push(a[i]);
		}
	}
	return q.top();
}
int main()
{
	cin>>n>>k;
	for(int i=0;i<n;i++)
	{
		cin>>a[i];
	}
	cout<<getk(a)<<endl;
	return 0;
}
