## 区间和 802

我们首先进行 n 次操作，每次操作将某一位置 x上的数加 c。

接下来，进行 m 次询问，每个询问包含两个整数 l 和 r，你需要求出在区间 [l,r] 之间的所有数的和。

```c++
#include <bits/stdc++.h>
using namespace std;
const int INF=1000086;
int a[INF],s[INF],n,m,res;
vector<pair<int, int > >add,query;
vector<int > all;
int find(int x)
{
	int l=0,r=all.size()-1;
	while(l<r)
	{
		int mid=l+r>>1;
		if(all[mid]>=x)r=mid;
		else l=mid+1;
	}
	return r+1;
}
int main()
{
	ios::sync_with_stdio(false);
    cin.tie(0);
	cin>>n>>m;
	for(int i=0;i<n;i++)
	{
		int x=0,c=0;
		cin>>x>>c;
		add.push_back({x,c});
		all.push_back(x);
	}
	for(int i=0;i<m;i++)
	{
		int l=0,r=0;
		cin>>l>>r;
		query.push_back({l,r});
		all.push_back(l);
		all.push_back(r);
	}
	sort(all.begin(),all.end());
	all.erase(unique(all.begin(),all.end()),all.end());
	for(int i=0;i<add.size();i++)
	{
		int x=find(add[i].first);
		a[x]+=add[i].second;
	}
	for(int i=1;i<=all.size();i++)s[i]=a[i]+s[i-1];
	for(int i=0;i<query.size();i++)
	{
		int l=find(query[i].first),r=find(query[i].second);
		cout<<s[r]-s[l-1]<<endl;

	}
	return 0;	
}
