const int N = 100086;
class Solution {
public:
    int h[N];   //堆
    int cur_size=0;   //size 记录的是堆当前的数据多少
    int panduan(int x,int y)
    {
        return h[x]>h[y];
    }

    // 下沉操作
    void down(int u) {
        int t = u;
        if (2 * u + 1 < cur_size && panduan(t, 2 * u + 1))
            t = 2 * u + 1;
        if (2 * u + 2 < cur_size && panduan(t, 2 * u + 2))
            t = 2 * u + 2;
        if (u != t) {
            swap(h[u], h[t]);
            down(t);
        }
    }

    // 上浮操作
    void up(int u) {
        while (u > 0 && panduan((u - 1) / 2, u)) {
            swap(h[(u - 1) / 2], h[u]);
            u = (u - 1) / 2;
        }
    }

    vector<int> sortArray(vector<int>& nums) {
        int n = nums.size();
        vector<int> res;
        for (int i = 0; i < n; i++) 
        {
            h[cur_size++] = nums[i];
            up(cur_size - 1);
        }
        while (n--) 
        {
            res.push_back(h[0]); // 将堆顶元素加入结果数组
            swap(h[0], h[--cur_size]); // 将堆顶元素与最后一个元素交换
            down(0); // 重新调整堆
        }
        return res;
    }
};
