```c++
class frequency
{
public:
    int num;
    int freq;
    frequency(int a, int b):num(a),freq(b){}
    bool operator<(const frequency &c)const
    {
        return freq>c.freq;//小根堆
    }
};
class Solution {
public:
    vector<int> topKFrequent(vector<int>& nums, int k) {
        unordered_map<int,int>umap;
        for(int x:nums)umap[x]++;
        priority_queue<frequency> q;
        vector<int>ans;
        for(auto& x:umap)
        {
            if(q.size()!=k)q.push({x.first,x.second});
            else
            {
                auto t=q.top();
                if(t.freq<x.second)
                {
                    q.pop();
                    q.push({x.first,x.second});
                }
            }
        }
        while(!q.empty())
        {
            ans.push_back(q.top().num);
            q.pop();
        }
        return ans;
    }
};
