### KY196 复数集合

一个复数（x+iy）集合，两种操作作用在该集合上：   1、Pop 表示读出集合中复数模值最大的那个复数，如集合为空 输出 empty ，不为空就输出最大的那个复数并且从集合中删除那个复数，再输出集合的大小SIZE；   2 Insert a+ib 指令（a，b表示实部和虚部），将a+ib加入到集合中 ，输出集合的大小SIZE；   最开始要读入一个int n，表示接下来的n行每一行都是一条命令。

```c++
#include<bits/stdc++.h>
using namespace std;

const int N=1e5+10;
class complexx
{
public:
    int real;
    int imag;
    complexx(int a, int b):real(a),imag(b){}
    bool operator<(const complexx &c)const
    {

        int yre=c.real;
        int yim=c.imag;
        if(real*real+imag*imag==yim*yim+yre*yre)
        {
            return imag>c.imag;
        }
        else
        {
            return real*real+imag*imag<yim*yim+yre*yre;
        }
    }
};

int main()
{
    int n;
    while(cin>>n)
    {
        priority_queue<complexx> q;
        while(n--)
        {
            string op;
            cin>>op;
            if(op=="Pop")
            {
                if(q.empty())
                {
                    cout<<"empty"<<endl;
                }
                else
                {
                    complexx cc=q.top();
                    q.pop();
                    cout<<cc.real<<"+i"<<cc.imag<<endl;

                    cout<<"SIZE = "<<q.size()<<endl;
                }
            }
            else
            {
                int a=0,b=0;
                scanf("%d+i%d",&a,&b);
                q.push(complexx(a,b));
                cout<<"SIZE = "<<q.size()<<endl;
            }
        }
    }
    return 0;
}
