    TreeNode() : val(0), left(-1), right(-1) {}
    TreeNode(int x) : val(x), left(-1), right(-1) {}
//    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
};
TreeNode tree[N];
vector<int> levelOrder(int root) 
{
        queue<int>q;
        vector<int>res;
        if(root!=-1)
        {
            q.push(root);
        }
        while(q.size())
        {
            int size=q.size();
            // vector<int>vec;
            for(int i=0;i<size;i++)
            {
                int t=q.front();
                q.pop();
//                cout<<t<<" ";
                res.push_back(t);
                if(tree[t].left!=-1)q.push(tree[t].left);
                if(tree[t].right!=-1)q.push(tree[t].right);
            }
            // res.push_back(vec);
        }
        return res;
}
void postOrder(int root, vector<int>& res)
{
	if(root==-1)
	{
		return;
	}
	postOrder(tree[root].left,res);
	postOrder(tree[root].right,res);
	res.push_back(root);
}
int main()
{
