### 846. 树的重心

给定一颗树，树中包含 n 个结点（编号 1∼n）和 n−1 条无向边。

请你找到树的重心，并输出将重心删除后，剩余各个连通块中点数的最大值。

重心定义：重心是指树中的一个结点，如果将这个点删除后，剩余各个连通块中点数的最大值最小，那么这个节点被称为树的重心。

```c++
int e[N],ne[N],h[N],vis[N];
void add(int a,int b)
{
	e[idx]=b,ne[idx]=h[a],h[a]=idx++;
}
int dfs(int u)
{
	vis[u]=1;
	int sum=1,res=0;
	for(int i=h[u];~i;i=ne[i])
	{
		int j=e[i];
		if(!vis[j])
		{
			int s=dfs(j);
			res=max(res,s);
			sum+=s;
		}
	}
	res=max(res,n-sum);
	ans=min(ans,res);
	return sum;
}
int main()
{
	ios::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);
    int a=0,b=0;
	cin>>n;
	memset(h,-1,sizeof(h));
	for(int i=0;i<n-1;i++)
	{
		cin>>a>>b;
		add(a,b);
		add(b,a);
	}
	dfs(1);
	cout<<ans<<endl;
	return 0;	
}
