void spfa()
{
    memset(dist, 0x3f, sizeof dist);
    dist[1]=0;
	queue<int >q;
	q.push(1);      
	st[1]=true;
    while (q.size())
    {
    	int t=q.front();
    	q.pop();
    	st[t]=false;
    	for(int i=h[t];~i;i=ne[i])
    	{
    		int j=e[i];
    		if(dist[j]>dist[t]+w[i])
    		{
    			dist[j]=dist[t]+w[i];
    			if(!st[j])
    			{
    				q.push(j);
    				st[j]=true;
				}
			}
		}
	}

    if (dist[n] == 0x3f3f3f3f) cout<<"impossible"<<endl;
    else cout<<dist[n] <<endl;
}
