### 最短路径问题

给你n个点，m条无向边，每条边都有长度d和花费p，给你起点s终点t，要求输出起点到终点的最短距离及其花费，如果最短距离有多条路线，则输出花费最少的。

```c++
#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int N=300086;
typedef pair<int, int> PII;
int n,m,s,t2;      // 点的数量
int h[N], w[N], e[N], ne[N], idx,cost[N];       // 邻接表存储所有边
int cnt[N];
int dist[N];        // 存储所有点到1号点的距离
bool st[N];     // 存储每个点的最短距离是否已确定
struct edge
{
    int to;
    int length;
    int money;
    edge(int t,int l,int m):to(t),length(l),money(m){}
};
vector<edge>graph[1010];
class pp
{
public:
    int fir;
    int sec;
    int cos;
    pp(int a,int b,int c):fir(a),sec(b),cos(c){}
     bool operator>(const pp &p)const
     {
        if(fir==p.fir)
        {
            return cos>p.cos;
        }
        else
        {
            return fir>p.fir;
        }
     }
};
// 求1号点到n号点的最短距离，如果不存在，则返回-1
int dij()
{
    memset(dist, 0x3f, sizeof dist);
    memset(cnt, 0x3f, sizeof cnt);
    dist[s] = 0;
    cnt[s]=0;
    priority_queue<pp, vector<pp>, greater<pp>> heap;
    heap.push({0, s,0});      // first存储距离，second存储节点编号
    while (heap.size())
    {
        auto t = heap.top();
        heap.pop();

        int node = t.sec, distance = t.fir,price=t.cos;

        if (st[node]) continue;
        st[node] = true;

        for (int i=0;i<graph[node].size();++i)
        {
            int new_node = graph[node][i].to;
            int len = graph[node][i].length;
            int p=graph[node][i].money;
            if (dist[new_node] > dist[node] + len||(dist[new_node] == dist[node] + len&&cnt[new_node]>p+cnt[node]))
            {
                dist[new_node] = dist[node] + len;
                cnt[new_node]=p+cnt[node];
                heap.push({ dist[new_node], new_node, cnt[new_node]});
            }
        }
    }

    if (dist[t2] == 0x3f3f3f3f) return -1;
    return dist[t2];
}

