### 858. Prim算法求最小生成树

含输出路径
$$
时间复杂度： O(n^2+m)
$$

```c++
#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
typedef pair<int, int> PII;
const int N = 510, INF = 0x3f3f3f3f;
int dist[N], g[N][N],pre[N];
int n, m;
bool st[N];
int res = 0;
int prim()
{
    memset(dist, 0x3f, sizeof dist);
    int res=0;
    dist[1]=0;
    for(int i=0;i<n;i++)
    {
    	int t=-1;
    	for(int j=1;j<=n;j++)
    	{
    		if(!st[j]&&(t==-1||dist[j]<dist[t]))
    		{
    			t=j;
			}
		}
		if(dist[t]==INF)return INF;
		st[t]=true;
		res+=dist[t];
		for(int j=1;j<=n;j++)
		{
			if(dist[j]>g[t][j]&&!st[j])
			{
				dist[j]=g[t][j];
				pre[j] = t;//从 t 到 j 的距离更短，i 的前驱变为 t.
			}			
		}
	}
	return res;
}
void getPath()//输出各个边
