void getPrime(vector<int>& factors, int n)
{
	for(int i=2; i<=n/i; i++)
    {
		while(n % i == 0)
        {
			factors[i]++;
			n /= i;
			if(n <= 1)
				return;
		}
	}
	if(n > 1)
		factors[n]++;
}

