	{
		for(int j=0;j<=9;j++)
		{
			for(int u=0;u<=9;u++)
			{
				if(j==u)f[i][j][u]+=pow(10,i-1);
				for(int k=0;k<=9;k++)
				{
					f[i][j][u]+=f[i-1][k][u];
				}
			}
		}
