int dp(int n,int u)
{
    if(n == 0) return u?0:1; //如果上界n是0，直接就是0种
    vector<int> nums; //存放n在B进制下的每一位
    B=10;
    while(n) nums.push_back( n% B) , n/= B;
    int ans = 0;
    int last = 0; 
    cout<<n<<endl;
    for(int i = nums.size()-1; i>= 0; i--)
    {
        int x = nums[i]; //取当前位上的数
		for(int j=(i==nums.size()-1);j<x;j++)
		{
			ans+=f[i+1][j][u];
		}
		ans+=x*last*pow(10,i);
		if(x==u)last++;
		if(!i)ans+=last;
		cout<<i<<":"<<last<<"endl"<<endl;
    }
	for(int i=1;i<nums.size();i++)
	{
		for(int j=1;j<=9;j++)
		{
			ans+=f[i][j][u];
		}
	}
	if(!u)ans+=f[1][u][u];
    return ans;
}

