```c++
#include<bits/stdc++.h>
#define debug(a) cout<<#a<<"="<<a<<endl
#define ll long long
using namespace std;
const int N=1e6+10; 
const ll INF=2E18;
int n,sz,ai,m;
struct node
{
	int e;
	int w;
};
int ans;
vector<node>edge[N];
int dfs(int u,int father)
{
	int dist=0;
	int d1=0,d2=0;
	for(int i=0;i<edge[u].size();i++)
	{
		int j=edge[u][i].e,w=edge[u][i].w;
		if(j==father) continue;
		int d=dfs(j,u) + w;
		dist=max(dist,d);//求f[x]的最大值
		//d1,d2求出以该点为顶点的最长路径
		if(d>=d1)d2=d1,d1=d;
		else if(d2<d)d2=d;
		//d1,d2求出以该点为顶点的最长路径
	}
	ans=max(ans,d1+d2);
	return dist;
}

