```c++
class Solution {
public:
    bool demo(int t, int i, const string& str, int target) 
    {
        if (i >= str.size()) 
        {
            return t == target;
        }
        if (t > target) 
        {
            return false;
        }
        int m=str.size();
        for (int j = 1; j <= 4; j++) 
        {
            int k=min(j, m-i);
            t += stoi(str.substr(i, k));
            if (demo(t, i + k, str, target)) 
            {
                // cout<<target<<endl;
                return true;
            }
            t -= stoi(str.substr(i, k) );
        }
        return false;
    }
    int punishmentNumber(int n) 
    {
        int res = 0;
        for (int i = 1; i <= n; i++) 
        {
            int t1 = i * i;
            string str = to_string(t1);
            if (demo(0, 0, str, i)) 
            {
                res += i * i;
            }
        }
        return res;
    }
};
