## [679. 24 点游戏](https://leetcode.cn/problems/24-game/)

https://leetcode.cn/problems/24-game/solutions/1/java-hui-su-jing-dian-mian-shi-ti-by-air-pj1k

```c++
const double TARGET = 24.0;
const double P = 1e-6;
const double EPISLON =1e-6;
class Solution { 
public:
    vector<double> calculate(double a, double b) {
        vector<double> list;
        list.push_back(a + b);
        list.push_back(a - b);
        list.push_back(b - a);
        list.push_back(a * b);
        if (abs(b) >= EPISLON) list.push_back(a / b);
        if (abs(a) >= EPISLON) list.push_back(b / a);
        return list;
    }
        bool helper(vector<double>& nums) 
        {
        if (nums.size() == 1) return abs(nums[0] - TARGET) < EPISLON;
        // 每次选择两个不同的数进行回溯
        for (int i = 0; i < nums.size(); i++) 
        {
            for (int j = i + 1; j < nums.size(); j++) 
            {
                // 将选择出来的两个数的计算结果和原数组剩下的数加入 next 数组
                vector<double> next;
                for (int k = 0; k < nums.size(); k++) 
                {
                    if (k != i && k != j) next.push_back(nums[k]);
                }
                for (double num : calculate(nums[i], nums[j])) 
                {
                    next.push_back(num);
                    if (helper(next)) return true;
                    next.pop_back(); // backtrack
                }
            }
        }
        return false;
    }
    bool judgePoint24(vector<int>& cards) 
    {
        if (cards.empty() || cards.size() != 4) return false;
        vector<double> nums(cards.size());
        for (int i = 0; i < 4; i++) 
        {
            nums[i] = (double)cards[i];
        }
        return helper(nums);
    }
};
```

输出表达式

```c++
const double TARGET = 24.0;
const double P = 1e-6;
class Solution {
private:
    struct Pair {
        double val;
        string expr;
        Pair(double v, string e) : val(v), expr(e) {}
    };

public:
    bool judgePoint24(vector<int>& cards) {
        if (cards.empty() || cards.size() != 4) return false;
        vector<double> a(4);
        vector<string> cur, ans;
        for (int i = 0; i < 4; ++i) {
            a[i] = cards[i];
            cur.push_back(to_string(cards[i]));
        }
        return solve(a, cur, ans);
    }

private:
    bool solve(vector<double>& a, vector<string>& cur, vector<string>& ans) 
    {
        int n = a.size();
        if (n == 1) 
        {
            if (abs(TARGET - a[0]) <= P) 
            {
                ans.push_back(cur[0]);
                // cout << "expression=" << ans[0] << endl;
                return true;
            }
            return false;
        }

        for (int i = 0; i < n; ++i) 
        {
            for (int j = i + 1; j < n; ++j) 
            {
                vector<double> b(n - 1);
                vector<string> cur2;
                int index = 0;
                for (int k = 0; k < n; ++k) 
                {
                    if (k != i && k != j) 
                    {
                        b[index++] = a[k];
                        cur2.push_back(cur[k]);
                    }
                }
                for (Pair p : compute(a, i, j, cur)) 
                {
                    b[index] = p.val;
                    cur2.push_back(p.expr);
                    if (solve(b, cur2, ans)) return true;
                    cur2.pop_back(); // backtrack reset state
                }
            }
        }
        return false;
    }

    vector<Pair> compute(vector<double>& a, int i, int j, vector<string>& cur) {
        double x = a[i], y = a[j];
        vector<Pair> ans;
        ans.emplace_back(x + y,  "(" + cur[i] + "+" + cur[j] + ")");
        ans.emplace_back(x - y,  "(" + cur[i] + "-" + cur[j] + ")");
        ans.emplace_back(y - x,  "(" + cur[j] + "-" + cur[i] + ")");
        ans.emplace_back(x * y,   cur[i] + "*" + cur[j]);
        if (y != 0) {
            ans.emplace_back(x / y,  "(" + cur[i] + "/" + cur[j] + ")");
        }
        if (x != 0) {
            ans.emplace_back(y / x, "(" + cur[j] + "/" + cur[i] + ")");
        }
        return ans;
    }
};
```



