                if(dfs(board,word,u+1,dx,dy,dp))return true;
                dp[dx][dy]=0;
            }
        }
        return false;
    }

    bool exist(vector<vector<char>>& board, string word) {
        int m=board.size();
        int n=board[0].size();
        vector<vector<int>> dp(m,vector<int>(n,0));
        for(int i=0;i<m;i++)
        {
            for(int j=0;j<n;j++)
            {
                dp[i][j]=1;
                if(dfs(board,word,0,i,j,dp))
