class Solution {
public:
    vector<vector<int>>res;
    vector<int>path;
    void dfs(vector<int>& candidates,int sindex,int sum,int target)
    {
        if(sum==target)
        {
            res.push_back(path);
            return;
        }
        if(sum>target)return;
        int n=candidates.size();
        for(int i=sindex;i<n;i++)
        {
            sum+=candidates[i];
            path.push_back(candidates[i]);
            dfs(candidates,i,sum,target);
            sum -= candidates[i];
            path.pop_back();
        }
    }
    vector<vector<int>> combinationSum(vector<int>& candidates, int target) {
        dfs(candidates,0,0,target);
        return res;
    }
};
