class Solution {
public:
    vector<string>res;
    string path;
    void dfs(int l,int r,int n)
    {
        if(l>n||l<r)return;//剪枝
        if(path.size()==n*2)
        {
            res.push_back(path);
            return;
        }
        for(int i=0;i<2;i++)
        {
            if(!i)
            {
                path+='(';
                dfs(l+1,r,n);
                path.pop_back();
            }
            else
            {
                path+=')';
                dfs(l,r+1,n);
                path.pop_back();
            }
        }

    }
    vector<string> generateParenthesis(int n) {
        dfs(0,0,n);
        return res;
    }
};
