{
	for(int i=0;i<4;i++)
	{
		swap(t[i],t[7-i]);
	}
	return t;
}
string move1(string t)
{
	for(int i=0;i<3;i++) swap(t[3],t[i]);
    for(int i=4;i<7;i++) swap(t[i],t[i+1]);
    return t;
