#include<algorithm>
using namespace std;
typedef pair <int,int> PII;
typedef pair <int,PII> PIII;
const int N=1010,INF=0x3f3f3f3f;
int dist[N],cnt[N];
int st[N];
int n,m;
int a,b,c;
int tt,ss,k;
struct edge
{
    int to;
    int length;
    edge(int t,int l):to(t),length(l){}
};
vector<PII>graph[N];
vector<PII>rgraph[N];
void dij()
{
    memset(dist, 0x3f, sizeof dist);
    dist[tt] = 0;
    priority_queue<PII, vector<PII>, greater<PII>> heap;
    heap.push({0, tt});      // first存储距离，second存储节点编号

    while (heap.size())
    {
        auto t = heap.top();
        heap.pop();

        int ver = t.second, distance = t.first;

        if (st[ver]) continue;
        st[ver] = true;

        for (int i = 0;i<rgraph[ver].size();i++)
        {
            int j = rgraph[ver][i].first;
            int w=rgraph[ver][i].second;
            if (dist[j] > distance + w)
            {
                dist[j] = distance + w;
                heap.push({dist[j], j});
            }
        }
    }

}
int astar()
{
	priority_queue <PIII,vector <PIII>,greater <PIII>> heap;
	heap.push({dist[ss],{0,ss}});
	while(heap.size())
	{
		auto t=heap.top();
		heap.pop();
		int ver=t.second.second,distance=t.second.first;
		cnt[ver]++;
		if(cnt[tt]==k)return distance;
		for(int i = 0;i<graph[ver].size();i++)
		{
			int j = graph[ver][i].first;
			int w = graph[ver][i].second;
			if(dist[j]<INF)
			{
				heap.push({distance+w+dist[j],{distance+w,j}});

			}
		}
	}
	return -1;
}

int main()
{
    cin>>n>>m;
    for(int i=0;i<m;i++)
    {
    	cin>>a>>b>>c;
    	graph[a].push_back({b, c});
        rgraph[b].push_back({a, c});
	}
