```c++
#include<iostream>
#include<cstdlib>
#include<cstdio>
#include<queue>
#include<string.h>
#include<cmath>
#include<algorithm>
#include<unordered_map>
using namespace std;
typedef pair <int,string> PII;
typedef pair <int,PII> PIII;
const int N=1010,INF=0x3f3f3f3f;
int dist[N],cnt[N];
int st[N];
int n,m;

int dir[4][2]={{-1,0},{1,0},{0,-1},{0,1}};
string c,start,x;

int f(string m)
{
	int dt=0;
	for(int i=0;i<9;i++)
	{
		if(m[i]!='x')
		{
			int t=m[i]-'1';
			dt=dt+abs(i/3-t/3)+abs(i%3-t%3);
		}
	}
	return dt;
}
string bfs()
{
	priority_queue<PII, vector<PII>, greater<PII>> heap;//小根堆,将元素的估计终点距离从小到大排序
	unordered_map<string,int >d;
	unordered_map<string,pair<string,char>> last;//存储一个元素由哪种状态,经过哪种操作得来,跟前面几题一样
	heap.push({f(start),start});
	char op[]="udlr";
	string end="12345678x";//终点
	d[start]=0;
	while(heap.size())
	{
		auto t=heap.top();
		heap.pop();
		string state=t.second;
		int cnt=d[state];
		if(t.second=="12345678x")break;
		int pos=state.find('x');
		int dx=pos/3,dy=pos%3;
		string init=state;
		for(int i=0;i<4;i++)
		{
			int xx=dx+dir[i][0];
			int yy=dy+dir[i][1];
			if(xx>=0&&xx<3&&yy>=0&&yy<3)
			{
				swap(state[pos],state[xx*3+yy]);
				if(!d.count(state)||d[state]>d[init]+1)
				{
					d[state]=d[init]+1;
					heap.push({f(state)+d[state],state});
					last[state]={init,op[i]};
				}
				swap(state[pos],state[xx*3+yy]);
			}
//			cout<<xx<<','<<yy<<endl;
		}
	}
	string ans;
	while(end!=start)
	{
		ans+=last[end].second;
		end=last[end].first;
	}
	reverse(ans.begin(),ans.end());//将其反转
	return ans;
}
int main()
{
	ios::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);
	for(int i=0;i<9;i++)
