#include<iostream>
#include<cstdlib>
#include<cstdio>
#include<queue>
#include<string.h>
#include<cmath>
#include<algorithm>
using namespace std;
const int N = 24, INF = 1e9;
const int maxn=1010;
//char g[maxn][maxn];
int n=0,m=0;
int res=INF,cnt;
int minv[maxn],mins[maxn],hh[maxn],rr[maxn];
void dfs(int u,int v,int s)
{
	if(v+minv[u]>n)return;//可行性

	if(s+mins[u]>=res)return;//最优解
	if(s+2*(n-v)/rr[u+1]>=res)return;
//	cout<<n<<" "<<m<<endl;
	if(!u)
	{
		if(v==n)res=s;
		return;
	} 
	for(int r=min(rr[u+1]-1,(int)sqrt((n-v)));r>=u;r--)
	{
		for(int h=min(hh[u+1]-1,(n-v)/r/r);h>=u;h--)
		{
			int t=0;
			//最底层的时候需要加上r*r
			if(u==m)t=r*r;
			rr[u]=r,hh[u]=h;
//			if(u==1)
//			cout<<u<<" "<<r<<" "<<h<<cnt++<<endl;
			dfs(u-1,v+r*r*h,s+2*r*h+t);
		}
	}
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		minv[i]=minv[i-1]+i*i*i;
		mins[i]=mins[i-1]+2*i*i;
	}
	//m+1层不存在，作为哨兵，减少边界情况的判断
	rr[m+1]=hh[m+1]=INF;
//	cout<<n<<m<<endl;
	dfs(m,0,0);
	if(res==INF)res=0;
	cout<<res<<endl;
    return 0;
}
