#### 写法1：

```c++
#include<iostream>
#include<cstdlib>
#include<cstdio>
#include<queue>
#include<string.h>
#include<cmath>
#include<algorithm>
using namespace std;
const int maxn=1010;

//char g[maxn][maxn];
int a[maxn];
int ans=100;
int n=0,w=0,k,sx,sy;
vector<vector<int> > g;
int path[maxn];

int dfs(int u,int depth)
{
	if(u>depth)return 0;
	if(u==depth)return path[u-1]==n;
	int st[maxn]={0};//定义在本层，只进行本层去重
	for(int i=u-1;i>=0;i--)
	{
		for(int j=i;j>=0;j--)
		{
			int s=path[i]+path[j];
			if(s > n || s <= path[u - 1] || st[s])continue;
			st[s]=1;
			path[u]=s;
			if(dfs(u+1,depth))return 1;
		}
	}
	return 0;
}
int main()
{
	path[0]=1;
	while(cin>>n&&n)
	{
		int dep=1;
		while(!dfs(1,dep))
		{
			dep++;
		}
		for(int i=0;i<dep;i++)
		{
			cout<<path[i]<<" ";
		}
		cout<<endl;
	}
    return 0;
}
