	for(int i=u-1;i>=0;i--)
	{
		for(int j=i;j>=0;j--)
		{
			int s=path[i]+path[j];
//			cout<<s<<endl;
			if(s > n || s <= path[u - 1] || st[s])continue;
//			cout<<s<<" u:"<<u<<" "<<path[u-1]<<" "<<depth<<endl;
			st[s]=1;
			path[u]=s;
			if(dfs(u+1,depth))return 1;
			st[s]=0;
		}
	}
	return 0;
}
