{
	path[0]=1;
	while(cin>>n&&n)
	{
		int dep=1;
		memset(st,0,sizeof(st));
		while(!dfs(1,dep))
		{
			dep++;

		}
		for(int i=0;i<dep;i++)
		{
			cout<<path[i]<<" ";
		}
		cout<<endl;
	}
    return 0;
}
