class Solution {
public:
    /**
     * 代码中的类名、方法名、参数名已经指定，请勿修改，直接返回方法规定的值即可
     *
     * 
     * @param head ListNode类 
     * @return ListNode类
     */
     vector<ListNode*> oddEvenList(ListNode* head) {
        // if(!head)return nullptr;
        ListNode* even=head->next;
        ListNode*evenHead=even;
        ListNode*odd=head;
        while(even&&even->next)
        {
            odd->next=even->next;
            odd=odd->next;
            even->next=odd->next;
            even=even->next;
        }
        odd->next=nullptr;
        vector<ListNode*> ans;
        ans.push_back(head);
        ans.push_back(evenHead);
        return ans;
    }
    ListNode* reverseList(ListNode* head) {
        ListNode* pre=nullptr;
        ListNode* cur=head;
        while(cur)
        {
            ListNode*nxt=cur->next;
            cur->next=pre;
            pre=cur;
            cur=nxt;
        }
        return pre;
    }
    ListNode* mergeTwoLists(ListNode* list1, ListNode* list2) {
        ListNode* dummy=new ListNode(INT_MIN);
        ListNode* rear=dummy;
        while(list1&&list2)
        {
            if(list1->val<list2->val)
            {
                rear->next=list1;
                list1=list1->next;
            }
            else
            {
                rear->next=list2;
                list2=list2->next;
            }
            rear=rear->next;
        }
        rear->next=(list1?list1:list2);
        return dummy->next;
    }
    ListNode* sortLinkedList(ListNode* head) {

        // write code here
        if(!head||!head->next)
        {
            return head;
        }
        vector<ListNode*> allHead=oddEvenList(head);
        allHead[1]=reverseList(allHead[1]);
        return mergeTwoLists(allHead[0],allHead[1]);
    }
};
