        }
        return cnt[p];
    }
    string longestWord(vector<string>& words) {
        memset(cnt,0,sizeof cnt);
        memset(son,0,sizeof son);
        idx = 0;
        string ans="";
        for(auto s:words)
        {
            insert(s);
        }
        for(auto s:words)
        {
            if(search(s)&&(ans.size()<s.size()||(s.size()==ans.size()&&ans>s)))
            {
                ans=s;
            }
        }
        return ans;
    }
};
```

### set+sort模拟

思路在官解

```c++
class Solution {
public:
    static bool cmp (const string & a, const string & b) 
        {
            if (a.size() != b.size()) 
            {
                return a.size() < b.size();
            } else 
            {
                return a > b;
            }
        }
    string longestWord(vector<string>& words) {
        sort(words.begin(), words.end(), &cmp);
        string longest = "";
        unordered_set<string> cnt;
        cnt.emplace("");
        for (auto & word : words) 
        {

            if (cnt.count(word.substr(0, word.size() - 1))) 
            {
                cnt.emplace(word);
                longest = word;
            }
        }
        return longest;
    }
};
```

