int dir[4][2]={{0,-1},{-1,0},{0,1},{1,0}};
class Trie {
private:

public:
    Trie* son[26];
    string s;
    Trie() {

        for(int i=0;i<26;i++)son[i]=nullptr;
    }
    //c++安全性
    ~Trie()
    {
        for(int i = 0; i < 26 ; i++)
        {
            if(son[i] != nullptr) delete son[i];
        }
    }
    void insert(string word) {
        Trie* root=this;
        for(int i=0;i<word.size();i++)
        {
            int u=word[i]-'a';
            if(root->son[u]==nullptr)root->son[u]= new Trie();
           root=root->son[u];
        }
        root->s=word;
    }

};
class Solution {
public:
    unordered_map<string, int> mp;
    // vector<string>ans;
    unordered_set<string> ans;
    Trie* root=new Trie();
    int dp[13][13] = {0};
    void dfs(vector<vector<char>>& board, Trie * node, int x,int y)
    {
        int dx=0,dy=0;
        int m=board.size();
        int n=board[0].size();
        if(node->s!= ""){
            ans.insert(node->s);
        }
		if(x>=m||y>=n||x<0||y<0)
		{
			return;
		}
        // if(u==word.size()-1&&board[x][y]==word[u])return true;//防止只有一个格子
        for(int i=0;i<4;i++)
        {
            dx=x+dir[i][0];
            dy=y+dir[i][1];

            if(dx>=0&&dx<m&&dy>=0&&dy<n&&!dp[dx][dy])
            {
                int u=board[dx][dy]-'a';
                if(node->son[u])
                {
                    dp[dx][dy]=1;

                    dfs(board,node->son[u],dx,dy);
                    dp[dx][dy]=0;
                }


            }
        }

    }

    vector<string> findWords(vector<vector<char>>& board, vector<string>& words) {
        int m=board.size();
        int n=board[0].size();

        for(auto w:words)root->insert(w);

        for(int i=0;i<m;i++)
        {
            for(int j=0;j<n;j++)
            {
                int u=board[i][j]-'a';
                if(root->son[u])
                {
                    dp[i][j]=1;

                    dfs(board,root->son[u],i,j);

                    dp[i][j]=0;
                }


            }
        }
        return vector<string>(ans.begin(), ans.end());
    }
};
