## 386 · 最多有k个不同字符的最长子字符串

```c++
class Solution {
public:
    /**
     * @param s: A string
     * @param k: An integer
     * @return: An integer
     */
    int lengthOfLongestSubstringKDistinct(string &s, int k) {
        // write your code here
        int l=0,r=0;
        unordered_map<char,int>umap;
        int ans=0;
        while(r<s.size())
        {
            umap[s[r]]++;
            while(umap.size()>k)
            {
                umap[s[l]]--;
                if(umap[s[l]]==0)
                {
                    umap.erase(s[l]);
                }
                l++;
            }
            ans=max(ans,r-l+1);
            r++;
        }
        return ans;
    }
};
