// 令f（n，m）表示n个盘子盛放m个苹果，注意到拿n-1个盘子（可以有空盘子）放m个苹果和n个盘子（无空盘子）放m个苹果无重复
// 所有有 子问题1：f(n,m)[容许有空盘子] = f(n-1,m)[容许有空盘子] + f(n,m)[无空盘子]
// 而什么时候n个盘子放m个苹果没有空盘子呢，就是n个盘子每个至少放一个：
// 所以有 子问题2： f(n,m)[无空盘子] = f(n,m-n) [容许有空盘子]
// 可以得到转移方程：f(n,m)[容许有空盘子] = f(n-1,m)[容许有空盘子] +f(n,m-n) [容许有空盘子]；
#include<bits/stdc++.h>
using namespace std;
int n=0,m=0;
long long v=0;
const int N = 15, mod = 1000000000;
int dp[N];
int main()
{
	int n;

    while(cin>>m>>n)
    {
        dp[0]=1;
        for(int i=1;i<=n;i++)
        {
            for(int j=i;j<=m;j++)
            {
                dp[j]=dp[j]+dp[j-i];
                // cout<<dp[j]<<" "<<j<<endl;
            }
            // cout<<endl;
        }
        cout<<dp[m]<<endl;
    }
    return 0;
}
