问题描述：输入3个子串， 输出这3个子串的最大公共子串
**输入：**
abcd acb abc
**输出：**
ab

```c++
#include<bits/stdc++.h>
using namespace std;
typedef long long ll;
typedef pair<int,int> pii;
const int INF=1E9,N=1e5 + 10;
string dp[110][110][110];
string a,b,c;
int ans=0,n=0,m=0,cnt=0;
int main()
{
//	cin>>n>>m;
	cin>>a>>b>>c;
	int n=a.size(),m=b.size(),len3=c.size();
	for(int i=0;i<=n;i++)
	{
		for(int j=0;j<=m;j++)
		{
			for(int k=0;k<=len3;k++)
			{
				dp[i][j][0]="";
				dp[i][0][k]="";
				dp[0][j][k]="";
			}

		}
	}	
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			for(int k=1;k<=len3;k++)
			{
				int leni=dp[i-1][j][k].size();
				int lenj=(dp[i][j-1][k].size());
				int lenk=(dp[i][j][k-1].size());
				if(a[i-1]==b[j-1]&&a[i-1]==c[k-1])
				{
					int now=(dp[i][j][k].size());
					int past=(dp[i-1][j-1][k-1].size());
					if(now<=past)
						dp[i][j][k]=dp[i-1][j-1][k-1]+a[i-1];

				}
				else
				{
					if(leni>=lenj&&leni>=lenk)
					{
						dp[i][j][k]=dp[i-1][j][k];
					}
					else if(lenj>=leni&&lenj>=lenk)
					{
						dp[i][j][k]=dp[i][j-1][k];
					}
					else 
					{
						dp[i][j][k]=dp[i][j][k-1];
					}

				}

//				cout<<i<<","<<j<<","<<k<<":"<<dp[i][j][k]<<endl;
			}

		}
	}
	cout<<dp[n][m][len3]<<endl;
	return 0;
}
