## [466. 回文日期](https://www.acwing.com/problem/content/description/468/)

```c++
#include<bits/stdc++.h>
using namespace std;
typedef long long ll;
string a,b;
int ans;
int mon[13]={0,31,28,31,30,31,30,31,31,30,31,30,31};
int isleap(int y)
{
	if((y%4==0&&y%100!=0)||(y%400==0))
	{
		return 1;
	}
	return 0;
}
int ok(int y,int m,int d)
{
	if(y/1000!=d%10)return 0;
	if(y/100%10!=d/10)return 0;
	if(y/10%10!=m%10)return 0;
	if(y%10!=m/10)return 0;
	return 1;
}
void getday(string a,string b)
{
	int y=stoi((a.substr(0,4)));
	int m=stoi((a.substr(4,2)));
	int d=stoi((a.substr(6,2)));
	int yb=stoi((b.substr(0,4)));
	int mb=stoi((b.substr(4,2)));
	int db=stoi((b.substr(6,2)));
//	ll day=d;
//	cout<<y<<" "<<m<<" "<<d<<endl;
	if(isleap(y))
	{
		mon[2]=29;
	}
	else
	{
		mon[2]=28;
	}
	while(1)
	{
		if(ok(y,m,d))ans++;
		if(y==yb&&m==mb&&d==db)break;
		d++;
		if(isleap(y))
		{
			mon[2]=29;
		}
		else
		{
			mon[2]=28;
		}
		if(d>mon[m])
		{
			m++;
			d=1;
		}
		if(m>12)
		{
			y++;
			m=1;
		}
	}
	cout<<ans<<endl;
}
int main()
{
	while(cin>>a>>b)
	{
		if(a>b)swap(a,b);
//		cout<<a<<" "<<b<<endl;
		getday(a,b);
	}
	return 0;
 } 
